import React, { useState } from 'react';
import Card from '../components/Card';
import ChatBot from '../components/ChatBot';
import Notification from '../components/Notification';

const Contact = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    subject: '',
    message: ''
  });
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState('');
  const [error, setError] = useState('');

  const clearMessages = () => {
    setError('');
    setSuccess('');
  };

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    clearMessages();

    try {
      // Call backend API
      const response = await contactAPI.submitContact(formData);

      if (response.data) {
        setLoading(false);
        setSuccess('Thank you for your message! We\'ll get back to you soon.');
        setFormData({
          name: '',
          email: '',
          subject: '',
          message: ''
        });

        // Reset success message after 3 seconds
        setTimeout(() => setSuccess(''), 3000);
      }
    } catch (error) {
      setError(apiUtils.formatErrorMessage(error));
      setLoading(false);
    }
  };

  const contactInfo = [
    {
      icon: '📞',
      title: 'Phone',
      details: ['+1 (555) 123-4567', '+1 (555) 123-4568'],
      description: 'Call us for immediate assistance'
    },
    {
      icon: '📧',
      title: 'Email',
      details: ['support@bikecare.com', 'info@bikecare.com'],
      description: 'Send us an email anytime'
    },
    {
      icon: '📍',
      title: 'Address',
      details: ['123 Service Street', 'City, State 12345'],
      description: 'Visit our main office'
    },
    {
      icon: '🕒',
      title: 'Business Hours',
      details: ['Mon-Fri: 8:00 AM - 8:00 PM', 'Sat-Sun: 9:00 AM - 6:00 PM'],
      description: 'We are here to help'
    }
  ];

  return (
    <div className="contact">
      <div className="container">
        {/* Header */}
        <section className="contact-header">
          <h1>Contact Us</h1>
          <p>Get in touch with our team. We're here to help with any questions or concerns.</p>
        </section>

        {/* Notifications */}
        {error && (
          <Notification
            type="error"
            message={error}
            onClose={clearMessages}
          />
        )}

        {success && (
          <Notification
            type="success"
            message={success}
            onClose={clearMessages}
          />
        )}

        {/* Contact Form */}
        <section className="contact-form-section">
          <Card className="contact-form-card">
            <h2>Send us a Message</h2>

            <form onSubmit={handleSubmit} className="contact-form">
              <div className="form-row">
                <FormInput
                  label="Full Name"
                  type="text"
                  name="name"
                  value={formData.name}
                  onChange={handleChange}
                  placeholder="Enter your full name"
                  required
                />
                <FormInput
                  label="Email Address"
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  placeholder="Enter your email"
                  required
                />
              </div>

              <FormInput
                label="Subject"
                type="text"
                name="subject"
                value={formData.subject}
                onChange={handleChange}
                placeholder="What is this regarding?"
                required
              />

              <FormInput
                label="Message"
                type="textarea"
                name="message"
                value={formData.message}
                onChange={handleChange}
                placeholder="Tell us how we can help you..."
                required
              />

              <Button
                type="submit"
                variant="primary"
                size="large"
                disabled={loading}
                className="contact-submit-btn"
              >
                {loading ? 'Sending...' : 'Send Message'}
              </Button>
            </form>
          </Card>
        </section>

        {/* Contact Information */}
        <section className="contact-info-section">
          <h2>Get in Touch</h2>
          <div className="contact-info-grid">
            {contactInfo.map((info, index) => (
              <Card key={`contact-${info.title}-${index}`} className="contact-info-card">
                <div className="contact-info-icon">{info.icon}</div>
                <h3>{info.title}</h3>
                <div className="contact-details">
                  {info.details.map((detail, idx) => (
                    <p key={`detail-${detail}-${idx}`}>{detail}</p>
                  ))}
                </div>
                <p className="contact-description">{info.description}</p>
              </Card>
            ))}
          </div>
        </section>

        {/* FAQ Section */}
        <section className="faq">
          <h2>Frequently Asked Questions</h2>
          <div className="faq-grid">
            <Card className="faq-card">
              <h3>How quickly can you service my bike?</h3>
              <p>Most services can be completed within 24-48 hours of booking, depending on the type of service and parts availability.</p>
            </Card>
            <Card className="faq-card">
              <h3>Do you provide doorstep service in all areas?</h3>
              <p>We currently serve 25+ cities. Check our service areas or contact us to see if we serve your location.</p>
            </Card>
            <Card className="faq-card">
              <h3>What payment methods do you accept?</h3>
              <p>We accept all major credit cards, debit cards, and digital payment methods for your convenience.</p>
            </Card>
            <Card className="faq-card">
              <h3>Is there a warranty on your services?</h3>
              <p>Yes, we provide a 30-day warranty on all our services and a 90-day warranty on parts we install.</p>
            </Card>
          </div>
        </section>
      </div>
    </div>
  );
};

export default Contact;
